impl GitRuntime {
    pub async fn ensure_available(&self) -> Result<()> {
        // 1. 先检查 Aether 自带的 Git（仅 Windows）
        if self.is_installed() {
            return Ok(());
        }

        // 2. 检查系统 PATH 中的 Git
        if Self::system_git_available() {
            return Ok(());
