        #[cfg(target_os = "macos")]
        return "Git not found. Install via: xcode-select --install\n  or: brew install git".into();

        #[cfg(target_os = "linux")]
        return "Git not found. Install via: apt install git\n  or: dnf install git".into();

        #[cfg(windows)]
        return "Git not found.".into();
